        "content": "import type { FC, JSX } from 'hono/jsx'\nimport { cn } from '@/lib/utils'\nimport { Avatar, AvatarFallback, AvatarImage } from '@/components/ui/avatar'\n\nconst sizeVariants = {\n  xs: '-space-x-1.5',\n  sm: '-space-x-2',\n  default: '-space-x-2.5',\n  lg: '-space-x-3',\n  xl: '-space-x-4',\n  '2xl': '-space-x-5',\n}\n\ntype AvatarStackProps = JSX.IntrinsicElements['div'] & {\n  avatars: { name: string; avatar?: string }[]\n  size?: keyof typeof sizeVariants\n  max?: number\n}\n\nexport const AvatarStack: FC<AvatarStackProps> = ({\n  avatars,\n  size = 'default',\n  max = 3,\n  class: className,\n  ...props\n}) => {\n  const visible = avatars.slice(0, max)\n  const overflow = avatars.length - max\n\n  return (\n    <div\n      data-slot=\"avatar-stack\"\n      class={cn('flex overflow-visible', sizeVariants[size], className)}\n      {...props}\n    >\n      {visible.map((avatar, i) => (\n        <Avatar key={i} size={size}>\n          {avatar.avatar ? (\n            <AvatarImage src={avatar.avatar} alt={avatar.name} />\n          ) : (\n            <AvatarFallback>\n              {avatar.name\n                .split(' ')\n                .map((n) => n[0])\n                .join('')}\n            </AvatarFallback>\n          )}\n        </Avatar>\n      ))}\n      {overflow > 0 && (\n        <Avatar size={size}>\n          <AvatarFallback>+{overflow}</AvatarFallback>\n        </Avatar>\n      )}\n    </div>\n  )\n}\n"
