        "content": "import type { FC, JSX, PropsWithChildren } from 'hono/jsx'\nimport { cn } from '@/lib/utils'\n\ntype FormFieldProps = PropsWithChildren<{\n  label?: string\n  description?: string\n  error?: string\n  required?: boolean\n  class?: string\n  id?: string\n}>\n\nexport const FormField: FC<FormFieldProps> = ({\n  label,\n  description,\n  error,\n  required = false,\n  class: className,\n  id,\n  children,\n}) => (\n  <div\n    data-slot=\"form-field\"\n    class={cn('space-y-2', className)}\n  >\n    {label && (\n      <FormLabel htmlFor={id} required={required}>\n        {label}\n      </FormLabel>\n    )}\n    {children}\n    {description && !error && (\n      <FormDescription>{description}</FormDescription>\n    )}\n    {error && (\n      <FormError>{error}</FormError>\n    )}\n  </div>\n)\n\ntype FormLabelProps = JSX.IntrinsicElements['label'] & {\n  required?: boolean\n}\n\nexport const FormLabel: FC<FormLabelProps> = ({\n  required = false,\n  class: className,\n  children,\n  ...props\n}) => (\n  <label\n    data-slot=\"form-label\"\n    class={cn(\n      'block text-sm font-medium leading-none',\n      'peer-disabled:cursor-not-allowed peer-disabled:opacity-70',\n      className\n    )}\n    {...props}\n  >\n    {children}\n    {required && (\n      <span class=\"ml-1 text-destructive\">*</span>\n    )}\n  </label>\n)\n\ntype FormDescriptionProps = JSX.IntrinsicElements['p']\n\nexport const FormDescription: FC<FormDescriptionProps> = ({\n  class: className,\n  children,\n  ...props\n}) => (\n  <p\n    data-slot=\"form-description\"\n    class={cn('text-sm text-foreground-muted', className)}\n    {...props}\n  >\n    {children}\n  </p>\n)\n\ntype FormErrorProps = JSX.IntrinsicElements['p']\n\nexport const FormError: FC<FormErrorProps> = ({\n  class: className,\n  children,\n  ...props\n}) => (\n  <p\n    data-slot=\"form-error\"\n    role=\"alert\"\n    class={cn('text-sm font-medium text-destructive', className)}\n    {...props}\n  >\n    {children}\n  </p>\n)\n"
